class Solution:
    def solve(self, s, k):
        n = len(s)
        res = n + 1
        i, j = 0, 0
        char_counts = {}
        unique_chars = set()
        k_used = 0
        while j < n:
            while j < n and k_used < k:
                if s[j] not in unique_chars:
                    unique_chars.add(s[j])
                    char_counts[s[j]] = 1
                else:
                    char_counts[s[j]] += 1
                    if char_counts[s[j]] > 1:
                        k_used += 1
                j += 1
            if j == n:
                res = min(res, n - i)
                break
            while k_used > k and i < j:
                if char_counts[s[i]] > 1:
                    char_counts[s[i]] -= 1
                    if char_counts[s[i]] == 1:
                        k_used -= 1
                elif s[i] in unique_chars:
                    unique_chars.remove(s[i])
                i += 1
            i += 1
        return res

