int minLen(int n, string& s, int k) {
    int res = n + 1;
    int i = 0, j = 0;
    unordered_map<char, int> char_counts;
    set<char> unique_chars;
    int k_used = 0;
    while (j < n) {
        while (j < n && k_used < k) {
            if (unique_chars.find(s[j]) == unique_chars.end()) {
                unique_chars.insert(s[j]);
                char_counts[s[j]] = 1;
            } else {
                char_counts[s[j]]++;
                if (char_counts[s[j]] > 1)
                    k_used++;
            }
            j++;
        }
        if (j == n)
            res = min(res, n - i);
        break;
        while (k_used > k && i < j) {
            if (char_counts[s[i]] > 1) {
                char_counts[s[i]]--;
                if (char_counts[s[i]] == 1)
                    k_used--;
            } else if (unique_chars.find(s[i]) != unique_chars.end()) {
                unique_chars.erase(s[i]);
            }
            i++;
        }
        i++;
    }
    return res;
}
